// // This module implements a 2-to-1 multiplexer with an enable signal. When the enable signal is high, the output is the value of signal b; when the enable signal is low, the output is the value of signal a.
module mux_2to1_enable (
  input [3:0] a,
  input [3:0] b,
  input en,
  output reg [3:0] mux_out
);

  always @(*) begin
    if (en)
      mux_out = a;
    else
      mux_out = b;
  end

endmodule
